class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def search_sublist(self, sublist_ll):
        # If the sublist is empty, it's considered to be present.
        if not sublist_ll.head:
            return True

        # If the main list is empty but the sublist is not, it cannot be found.
        if not self.head:
            return False

        current_main = self.head

        while current_main:
            temp_main = current_main
            temp_sub = sublist_ll.head

            # Attempt to match the sublist starting from current_main
            while temp_sub:
                # If we run out of nodes in the main list or find a mismatch
                if not temp_main or temp_main.data != temp_sub.data:
                    break
                temp_main = temp_main.next
                temp_sub = temp_sub.next

            # If temp_sub became None, it means the entire sublist was matched
            if not temp_sub:
                return True

            current_main = current_main.next

        # If we traversed the entire main list and didn't find the sublist
        return False
